var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>\\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>\\nRecording file DTBD by #166774","JPN":"AEGIS 8 PBLIT SECURITY SEQUENCE：<color=#ffd34c>ACTIVATED</color>\\nADC FACTOR：<color=#ffd34c>ALPHA CONFIRMED</color>\\nRecording file DTBD by #166774","ENG":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>\\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>\\nRecording file DTBD by #166774","TWN":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>\\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>\\nRecording file DTBD by #166774"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"무슨 딸아이 일기장 훔쳐 보는 듯한 표정을 짓고 계시네요.","JPN":"娘の日記を隠れて読んでいるような顔をしてますよ。","ENG":"You look like you're peeping at your daughter's diary.","TWN":"您露出了一副偷看女兒日記的表情呢。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"음? 언제부터 거기에 있었나?","JPN":"うん？　いつからそこにいたのだ？","ENG":"Hmm? When did you arrive?","TWN":"嗯？你是什麼時候在這裡的？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"방금 전에 들어왔습니다. 뭐 재미있는 거라도 있으신가요?","JPN":"今来たところです。何か面白いものでも？","ENG":"I just came in. Did you find something fun?","TWN":"我剛進來的，發生了什麼有趣的事情嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"아, 아카데미 편입생들 중에 흥미로운 친구가 하나 있어서 말이야.","JPN":"あぁ、アカデミー編入生の中で興味深い子がいてな。","ENG":"Oh, I just found an interesting transfer student at the Academy.","TWN":"是啊，學院的轉學生裡有位非常有趣的朋友呢。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"자네도 한 번 보게.","JPN":"君も見てみるといい。","ENG":"Take a look.","TWN":"你也來看看吧。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"이건...... 확실히 흥미롭군요.","JPN":"これは……確かに興味深いですね。","ENG":"This is... definitely interesting.","TWN":"這是……確實很有趣。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"과다행운 능력자라니, 이런 건 <color=#ff3636>[DATA EXPUNGED]</color> 시절에도 거의 본 적이 없는데 말이죠.","JPN":"幸運過多の能力者とは、これは\\n<color=#ff3636>[DATA EXPUNGED]</color>の頃でもあまり見たことはありませんね。","ENG":"An ability that grants excessive luck? I've never seen someone like this even during the <color=#ff3636>[DATA EXPUNGED]</color> days.","TWN":"超級好運的能力者，這種能力在<color=#ff3636>[DATA_EXPUNGED]</color>時代幾乎沒見過呢。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그래. 아주 희귀한 케이스지.","JPN":"あぁ、非常に珍しいケースだ。","ENG":"Yes. A very rare case indeed.","TWN":"是啊，非常罕見的案例。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"밖으로 보이는 능력이 아니라서 확인 자체가 어려운데 이렇게 찾아낸 건 운이 좋았다고 해야겠지.","JPN":"外に見える能力ではないから確認自体が難しいというのに、このように見つけ出せたのは運がよかったとしか言いようがないだろう。","ENG":"We were lucky to find someone like this, seeing as the ability can't be visually identified.","TWN":"居然能找出這種從外表看不出能力，本身又很難確認的能力者，只能說運氣真的很好。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"아니면...... 운이 좋도록 <color=#ffd34c>변경</color>되었을 수도 있겠죠.","JPN":"それか……運が良くなるよう<color=#ffd34c>変更</color>されたのかもしれませんね。","ENG":"Or... Perhaps the luck <color=#ffd34c>changed</color> to guide us to this result.","TWN":"或者……運氣是被<color=#ffd34c>變成</color>很好的也說不定。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"확실히...... 그럴 수도 있겠군.","JPN":"確かに……その可能性もある。","ENG":"I can definitely... see that as a possibility.","TWN":"確實……是有可能做到那種事。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"이런 종류의 능력들이 위험한 건 바로 이것 때문입니다.","JPN":"このような種類の能力者たちが危険なのは、まさにこのせいです。","ENG":"That's the reason why these sort of abilities are so dangerous.","TWN":"這種能力危險的原因就是這個。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"현실이 어떻게 바뀌었는지, 애초에 무엇이 현실이었는지조차 혼란스럽게 만들죠.","JPN":"現実がどのように変わったか、そもそも何が現実だったのかさえわからず、\\n混乱を招いてしまいます。","ENG":"It becomes difficult to identify how reality has changed, or even figure out what really happened.","TWN":"現實是如何改變的，還有最初的現實是什麼，也都很讓人混亂。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"아직까지는 그리 위험한 징후는 없는 것 같지만 최소한 <color=#ffd34c>2급 이</color>","JPN":"今のところはそこまで危険な兆候はありませんが、少なくとも<color=#ffd34c>2級以</color>","ENG":"Although there haven't been any dangerous signs, we should place her as a <color=#ffd34c>Class 2 or hi—</color>","TWN":"雖然目前為止還沒有什麼危險的跡象，但至少要把她列為<color=#ffd34c>2級</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"아직까지는 그리 위험한 징후는 없는 것 같지만 최소한 <color=#ffd34c>2급 이하 경계대상</color>으로 놓고 주시해야 할 겁니다.","JPN":"今のところはそこまで危険な兆候はありませんが、少なくとも\\n<color=#ffd34c>2級以下警戒対象</color>に指定して、注視すべきかと思います。","ENG":"Although there haven't been any dangerous signs, we should place her as a <color=#ffd34c>Class 2 or lower Alert Target</color> and maintain surveillance.","TWN":"雖然目前為止還沒有什麼危險的跡象，但至少要把她列為<color=#ffd34c>2級</color>以下的警戒對象進行觀察。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"동감이네. 요주의 인물이니만큼 <color=#ff3636>최대한 신경을</color>","JPN":"同感だ。要注意人物とだけあって<color=#ff3636>できるだけ気を</color>","ENG":"I agree. Since her abilities are questionable, we should <color=#ff3636>try our best to—</color>","TWN":"我同意。作為需要警戒的對象，最好要<color=#ff3636>密切注意</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"동감이네. 요주의 인물이니만큼 <color=#ff3636>최대한 신경을 쓰지 말고 잊어버리는</color> 게 좋겠지.","JPN":"同感だ。要注意人物とだけあって<color=#ff3636>できるだけ気を使わずに忘れてしまう</color>方が\\nいいだろう","ENG":"I agree. Since her abilities are questionable, we should <color=#ff3636>try our best to forget about her</color>.","TWN":"我同意。作為需要警戒的對象，最好要<color=#ff3636>儘可能地忘記</color>。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"그러고 보니 저희 방금 무슨 이야기를 하고 있었죠?","JPN":"そういえば、私たちは今……何を話していたのでしょうか？","ENG":"What were we talking about just now?","TWN":"話說我們剛才在討論什麼來著？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"나도 요즘 건망증이 심해져서 깜박깜박 한다네. 뭐 별로 중요한 이야기는 아니었던 것 같군.","JPN":"私も最近物忘れが激しくてな。まぁ、重要な話ではなかったはずだ。","ENG":"I've been very forgetful lately. I guess it wasn't anything important.","TWN":"看來我最近健忘症變嚴重了，不過好像不是什麼重要的事情。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"그럼 전 가 보겠습니다. 다음 보고에서 뵙도록 하죠.","JPN":"それでは私は失礼します。次の報告時間に伺います。","ENG":"Well then, I'll leave now. I will see you at the next briefing.","TWN":"那我先走了，下次報告時再見吧。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그래 수고하게나.","JPN":"あぁ、ご苦労だった。","ENG":"Yes, keep up the good work.","TWN":"好，辛苦了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"GAP_BTYPE_NULL_NULL","text":{"KOREA":"<color=#ff3636>원격 조작 모드 종료. 긴급 사태 발생에 따른 자율 모드 활성화.</color>","JPN":"<color=#ff3636>遠隔操作モード終了。緊急事態発生による自律モードをアクティベーション。</color>","ENG":"<color=#ff3636>End remote control mode. Activating autonomous mode in response to urgent crisis.</color>","TWN":"<color=#ff3636>遠端操作模式結束。由於發生緊急事態，啟動自律模式。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_SYS_START1"},{"id":"L31_1","type":"dialog","speaker":"GAP_BTYPE_NULL_NULL","text":{"KOREA":"<color=#ff3636>관리국 표준시각 기준 3분 24초 전, 제 3종 정보오염이 관측되었습니다. </color>","JPN":"<color=#ff3636>管理局の標準時刻基準3分24秒前、第3種情報汚染が観測されました。</color>","ENG":"<color=#ff3636>Based on the Administration standard time, a Category 3 data corruption was observed 3m 24s ago. </color>","TWN":"<color=#ff3636>管理局標準時間3分24秒前，觀測到第3種情報污染。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L32_1","type":"dialog","speaker":"GAP_BTYPE_NULL_NULL","text":{"KOREA":"<color=#ff3636>간섭타입은 자기보호, 현재 위험도는 낮습니다. </color>","JPN":"<color=#ff3636>干渉タイプは自己防衛、現在の危険度は低いです。</color>","ENG":"<color=#ff3636>Interference type is self-defense. Current threat is low. </color>","TWN":"<color=#ff3636>干涉類型是自我保護，當前威脅度低。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L33_1","type":"dialog","speaker":"GAP_BTYPE_NULL_NULL","text":{"KOREA":"<color=#ff3636>오염된 정보를 복구합니다.</color>","JPN":"<color=#ff3636>汚染された情報を復旧します。</color>","ENG":"<color=#ff3636>Recovering corrupted data.</color>","TWN":"<color=#ff3636>正在復原受污染的情報。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L34_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"......벌써 여기까지 능력이 개화했다니, 정말 흥미로운 친구로군.","JPN":"……もうここまで能力が開花しているとは、実に興味深い子だ。","ENG":"She already developed her ability this much. How interesting.","TWN":"……已經把能力提升到了這個地步，真是位有趣的朋友啊。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"아직은 괜찮은 것 같지만...... 이런 능력은 질량 보존의 법칙이라는 게 작용하기 마련이라서......","JPN":"まだ問題はなさそうだが……\\nこのような能力は質量保存の法則が働いてしまう……","ENG":"It's still okay for now... But the law of conservation is usually applied for abilities like this...","TWN":"雖然現在還沒問題……但這種能力是根據質量守恆定律作用的……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"이 아이에게 행운이 작용할 때마다 주변에 항상 안 좋은 일이 따라붙게 되겠지.","JPN":"この子に幸運が降りかかるたびに、周囲に悪いことが起こるのだ。","ENG":"Whenever she gets lucky, someone else is bound to experience misfortune.","TWN":"每當幸運發生在這孩子身上時，周圍就會跟著發生不好的事情。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"우연히 동전을 줍게 되면, 누군가는 그 동전을 잃어 버린 셈이니까.","JPN":"偶然お金を拾えば、誰かはそのお金を落としたことになる。","ENG":"Just like how when a coin is found, there is another person who lost that coin.","TWN":"如果偶然撿到硬幣，那麼就會有人丟失硬幣。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"최소한 누군가에게 강도로 몰리지 않도록 조금 더 신경을 써 줘야겠는걸?","JPN":"少なくとも、誰かさんに強盗扱いされないよう、\\nもう少し気をつけた方が良さそうだ。","ENG":"Someone should make sure that she's not framed as a thief.","TWN":"所以至少要多注意一點，免得被別人當成強盜。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};